const fs = require('fs');
const path = require('path');
const childProcess = require('child_process');

// Set environment variables
process.env.NODE_ENV = 'production';

// Install dependencies
console.log('Installing dependencies...');
childProcess.execSync('npm install', { stdio: 'inherit' });

// Run tests
console.log('Running tests...');
childProcess.execSync('npm run test', { stdio: 'inherit' });

// Build the application
console.log('Building the application...');
const buildCommand = `npm run build`;
childProcess.execSync(buildCommand, { stdio: 'inherit' });

// Generate SBOM (Software Bill of Materials)
console.log('Generating SBOM...');
const sbomPath = path.join(__dirname, 'sbom.json');
fs.writeFileSync(sbomPath, JSON.stringify({
  dependencies: childProcess.execSync('npm ls --json', { encoding: 'utf8' }),
}));

// Deploy to production
console.log('Deploying to production...');
const deployCommand = `npm run deploy`;
childProcess.execSync(deployCommand, { stdio: 'inherit' });